```hcl
variable "environments" {
  default = {
    dev = {
      instance_type = "t2.micro"
      instance_count = 1
      enable_monitoring = false
    }
    staging = {
      instance_type = "t2.small"
      instance_count = 2
      enable_monitoring = true
    }
    prod = {
      instance_type = "t3.medium"
      instance_count = 3
      enable_monitoring = true
    }
  }
}

locals {
  # Flatten environments for for_each
  instances = flatten([
    for env, config in var.environments : [
      for i in range(config.instance_count) : {
        key           = "${env}-${i}"
        environment   = env
        instance_type = config.instance_type
        monitoring    = config.enable_monitoring
      }
    ]
  ])

  instance_map = { for inst in local.instances : inst.key => inst }
}

resource "aws_instance" "servers" {
  for_each = local.instance_map

  ami           = "ami-0c55b159cbfafe1f0"
  instance_type = each.value.instance_type

  monitoring = each.value.monitoring

  tags = {
    Name        = "server-${each.key}"
    Environment = each.value.environment
  }
}

# Conditional resource creation
resource "aws_cloudwatch_metric_alarm" "cpu" {
  for_each = {
    for k, v in local.instance_map : k => v if v.monitoring
  }

  alarm_name          = "high-cpu-${each.key}"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 2
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = 300
  statistic           = "Average"
  threshold           = 80
  alarm_description   = "CPU utilization exceeds 80%"
}

output "server_ids" {
  value = { for k, v in aws_instance.servers : k => v.id }
}
