```hcl
resource "aws_instance" "web" {
  ami           = "ami-0c55b159cbfafe1f0"
  instance_type = "t2.micro"
  key_name      = "my-key"

  tags = {
    Name = "WebServer"
  }
}

# Provisioner: install software after creation
resource "null_resource" "setup_web" {
  triggers = {
    instance_id = aws_instance.web.id
  }

  connection {
    type        = "ssh"
    user        = "ubuntu"
    private_key = file("~/.ssh/my-key.pem")
    host        = aws_instance.web.public_ip
  }

  provisioner "file" {
    source      = "scripts/setup.sh"
    destination = "/tmp/setup.sh"
  }

  provisioner "remote-exec" {
    inline = [
      "chmod +x /tmp/setup.sh",
      "sudo /tmp/setup.sh"
    ]
  }
}

# Local provisioner: run command on Terraform runner
resource "null_resource" "notify" {
  triggers = {
    instance_id = aws_instance.web.id
  }

  provisioner "local-exec" {
    command = "echo 'Server ${aws_instance.web.id} created' >> deployment.log"
  }
}

# External data source: call any script
data "external" "get_latest_ami" {
  program = ["python3", "${path.module}/scripts/get_ami.py"]

  query = {
    region = "us-east-1"
    os     = "ubuntu"
  }
}

# Null resource with triggers for API call
resource "null_resource" "invalidate_cdn" {
  triggers = {
    # Re-run when the instance changes
    deploy_time = timestamp()
  }

  provisioner "local-exec" {
    command = "aws cloudfront create-invalidation --distribution-id E1234 --paths '/*'"
  }
}
