  tags = {
    Name = "${var.environment}-public-${count.index + 1}"
  }
}

resource "aws_s3_bucket" "logs" {
  count  = local.is_prod ? 1 : 0
  bucket = "${var.environment}-vpc-flow-logs"
}

output "vpc_id" {
  value = aws_vpc.main.id
}

output "public_subnet_ids" {
